// Handle both direct webhook and sub-workflow calls
const raw = $input.first().json;
const data = raw.body || raw;
const { ideaPrompt = '', briefId = '' } = data;

// Build competitive search queries
const baseIdea = ideaPrompt.slice(0, 100);
const queries = [
  `${baseIdea} competitors alternatives`,
  `${baseIdea} market analysis comparison`,
  `best ${baseIdea} tools software 2025 2026`
];

return queries.map(q => ({ json: { query: q, briefId } }));

// Process competitive analysis results
const allSources = [];

for (const item of $input.all()) {
  const data = item.json;

  // Process DuckDuckGo Instant Answer topics
  const topics = data?.RelatedTopics || [];
  for (const topic of topics.slice(0, 3)) {
    if (!topic.Text && !topic.FirstURL) continue;

    allSources.push({
      sourceType: 'webpage',
      url: topic.FirstURL || '',
      title: (topic.Text || 'Competitive Result').slice(0, 500),
      snippet: (topic.Text || '').slice(0, 300),
      trustScore: 45, // Moderate trust for web search results
      rawPayload: {
        source: 'n8n',
        workflowType: 'competitive_analysis',
        icon: topic.Icon?.URL
      }
    });
  }

  // Process Abstract (if available)
  if (data?.Abstract && data?.AbstractURL) {
    allSources.push({
      sourceType: 'webpage',
      url: data.AbstractURL,
      title: data.Heading || 'Competitive Overview',
      snippet: data.Abstract.slice(0, 300),
      trustScore: 55,
      rawPayload: {
        source: 'n8n',
        workflowType: 'competitive_analysis',
        abstractSource: data.AbstractSource
      }
    });
  }
}

// Deduplicate by URL
const seen = new Set();
const unique = allSources
  .filter(s => s.url)
  .filter(s => {
    if (seen.has(s.url)) return false;
    seen.add(s.url);
    return true;
  })
  .sort((a, b) => b.trustScore - a.trustScore)
  .slice(0, 8);

return [{ json: {
  sources: unique,
  metadata: {
    workflowName: 'nexus-competitive-analysis',
    totalResults: allSources.length,
    uniqueSources: unique.length
  }
}}];
